mapper.delete:
delete
from test_declaration_product
where plan_id = #{planId,jdbcType=BIGINT} and product_id = #{productId,jdbcType=BIGINT}

mapper.update:
update test_declaration_product
set product_type    = #{productType,jdbcType=VARCHAR},
    product_index   = #{productIndex,jdbcType=VARCHAR}
where
      plan_id = #{planId,jdbcType=BIGINT}
  AND product_id = #{productId,jdbcType=BIGINT}

mapper.select:
SELECT * FROM test_declaration_product WHERE plan_id = #{planId,jdbcType=BIGINT}
AND product_name LIKE concat(concat('%',#{productName}),'%')
AND product_type LIKE concat(concat('%',#{productType}),'%')
